{"npsn":"014001","name":"Akademi Perniagaan dan Perusahaan APIPSU Medan","address":"Jalan Jambi No 59","village":"Namu Gajah","status":"Swasta","jenjang":"UNIVERSITAS","district":"Medan Tuntungan","regencyBpsCode":"1271","regencyName":"Kota Medan","provinceName":"Sumatera Utara","school_id":"6c9e22c1-d254-42e7-858b-83ff3c89eda7","user_id":"524025bf-21b7-4475-a26f-a2ca08b1d257","password_hash":"$2b$04$wrdUdKlL70DFt.s8Z1APNuqmXbfSJ0vQD0HgISG1JSaiPIfV12zJy"},
